def bucketSort(nums: List[int]) -> List[int]:
    if not nums:
        return nums
    min_val, max_val = min(nums), max(nums)
    if min_val == max_val:
        return nums
    n = len(nums)
    buckets = [[] for _ in range(n)]
    for x in nums:
        idx = int((x - min_val) / (max_val - min_val) * (n - 1))
        buckets[idx].append(x)
    res = []
    for b in buckets:
        res.extend(sorted(b))
    return res

